-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH final_data AS (
  SELECT
    *,
    -- Calculate MD5_ID_TARGET
    IFF(
      SRC_REGSTRD = 'N',
      MD5_ID_TARGET_NONRGSTRD,
      in_MD5_ID_TARGET
    ) AS MD5_ID_TARGET,

    -- Calculate TYPE_2_FLG
    CASE
      WHEN IFF(SRC_REGSTRD = 'N', MD5_ID_TARGET_NONRGSTRD, in_MD5_ID_TARGET) = MD5_ID_SOURCE THEN '1'
      WHEN IFF(SRC_REGSTRD = 'N', MD5_ID_TARGET_NONRGSTRD, in_MD5_ID_TARGET) != MD5_ID_SOURCE THEN '2'
      ELSE '0'
    END AS TYPE_2_FLG

  FROM {{ ref('int_final_gather') }}
)

SELECT
  *,
  -- Router group logic
  CASE
    WHEN I_U_FLG = 'I' THEN 'INSERT'
    WHEN I_U_FLG = 'U' AND TYPE_2_FLG = '1' THEN 'UPDATE'
    WHEN I_U_FLG = 'U' AND TYPE_2_FLG = '2' THEN 'TYPE_2'
    ELSE 'DEFAULT'
  END AS ROUTER_GROUP

FROM final_data
